library(shiny)

# --- UI ---
ui <- fluidPage(
  tags$head(
    # Google Analytics
    tags$script(async = NA, src = "https://www.googletagmanager.com/gtag/js?id=G-JT56Q0HQGV"),
    tags$script(HTML("
      window.dataLayer = window.dataLayer || [];
      function gtag(){dataLayer.push(arguments);}
      gtag('js', new Date());
      gtag('config', 'G-JT56Q0HQGV');
    ")),
    
    tags$style(HTML("
      input[type=number]::-webkit-inner-spin-button, 
      input[type=number]::-webkit-outer-spin-button { -webkit-appearance: none; margin: 0; }
      input[type=number] { -moz-appearance: textfield; }
      .status-warning { color: red; font-weight: bold; margin-bottom: 10px; font-size: 0.85em; }
      .battle-log { background-color: #f8f9fa; border: 1px solid #ddd; padding: 15px; height: 500px; overflow-y: auto; font-family: 'Courier New', monospace; white-space: pre-wrap; }
      .description-text { line-height: 1.2; margin-bottom: 20px; font-size: 1em; }
      .footer-text { line-height: 1.4; margin-top: 40px; margin-bottom: 40px; font-size: 0.9em; color: #555; }
      
      /* スマホ対応 */
      @media (max-width: 768px) {
        .battle-log { height: 400px; font-size: 0.9em; }
        h1 { font-size: 1.5em; }
        .btn { padding: 10px; font-size: 1.1em; }
      }
      
      /* シェアボタン */
      .btn-share { background-color: #1DA1F2; color: white; border: none; margin-top: 100px; width: 100%; font-weight: bold; }
      .btn-share:hover { background-color: #1991db; color: white; }
    ")),
    tags$script(HTML("
      $(document).on('shiny:connected', function() {
        setInterval(function() { $('.battle-log').each(function() { this.scrollTop = this.scrollHeight; }); }, 200);
      });
    "))
  ),
  
  h1("JBSクエスト・トリビュート"),
  
  div(class = "description-text",
      "任意のヒットポイント，攻撃力，守備力，素早さのキャラクターを生成してバトルさせる無料のオンラインゲームです．", br(),
      "それぞれのステータスの最小値は0，最大値は100ですが，4つのステータスの合計値は100以下でなければなりません．", br(),
      br(),
      "モード1では，あなたのキャラクターが7人の強豪と戦って，7連勝したらクリアです．", br(),
      "モード2では，任意のステータスをもつ2つのキャラクターを自由に対戦させることができます．", br(),
      br(),
      "すべて入力し終えたら，「チャレンジ開始!」ボタンまたは「対戦開始!」ボタンを押してください．", br(),
      "「次のターンへ」ボタンを押すと，戦闘の様子が1ターンずつ表示されます．", br(),
      "パソコンでは画面の右に，スマホでは画面の下に戦闘ログが表示されます．", br(),
      br(),
      "JBSクエスト・トリビュートのアルゴリズムの考え方と根拠については，",tags$a(href="https://sites.google.com/view/takahashistat/profile/jbsquesttribute", "JBSクエスト・トリビュートのアルゴリズム", target="_blank", rel="noopener noreferrer"),"において説明をしています．", br(),
      br(),
      "キャラクターのステータス設定について悩む方は，",tags$a(href="https://jbsmemorial.sakura.ne.jp/etc/quest1.html", "JBSクエストの記録", target="_blank", rel="noopener noreferrer"),"と",
      tags$a(href="https://jbsmemorial.sakura.ne.jp/etc/quest2.html", "JBSクエスト2の記録", target="_blank", rel="noopener noreferrer"),"も参考にしてください．"
      
  ),
  
  hr(),
  
  tabsetPanel(
    tabPanel("モード1: 7連勝チャレンジ",
             sidebarLayout(
               sidebarPanel(width = 4,
                            textInput("m1_name", "あなたのキャラクターの名前", value = ""),
                            numericInput("m1_hp", "ヒットポイント(HP)", value = NA, min = 0),
                            numericInput("m1_atk", "攻撃力(ATK)", value = NA, min = 0),
                            numericInput("m1_def", "守備力(DEF)", value = NA, min = 0),
                            numericInput("m1_spd", "素早さ(SPD)", value = NA, min = 0),
                            uiOutput("warning_m1"),
                            hr(),
                            actionButton("start_m1", "チャレンジ開始！", class = "btn-primary", width = "100%"),
                            uiOutput("next_btn_ui_m1"),
                            uiOutput("share_ui_m1")
               ),
               mainPanel(width = 8, 
                         strong("戦闘ログ"),
                         div(class = "battle-log", verbatimTextOutput("log_m1")))
             )
    ),
    tabPanel("モード2: 自由対戦",
             sidebarLayout(
               sidebarPanel(width = 4,
                            fluidRow(
                              column(6, textInput("m2_n1", "キャラ1の名前", ""), numericInput("m2_h1", "ヒットポイント(HP)", NA), numericInput("m2_a1", "攻撃力(ATK)", NA), numericInput("m2_d1", "守備力(DEF)", NA), numericInput("m2_s1", "素早さ(SPD)", NA)),
                              column(6, textInput("m2_n2", "キャラ2の名前", ""), numericInput("m2_h2", "ヒットポイント(HP)", NA), numericInput("m2_a2", "攻撃力(ATK)", NA), numericInput("m2_d2", "守備力(DEF)", NA), numericInput("m2_s2", "素早さ(SPD)", NA))
                            ),
                            uiOutput("warning_m2"),
                            hr(),
                            actionButton("start_m2", "対戦開始！", class = "btn-success", width = "100%"),
                            uiOutput("next_btn_ui_m2"),
                            uiOutput("share_ui_m2")
               ),
               mainPanel(width = 8, 
                         strong("戦闘ログ"),
                         div(class = "battle-log", verbatimTextOutput("log_m2")))
             )
    )
  ),
  
  # --- フッター ---
  hr(),
  div(class = "footer-text",
      "制作者：", tags$a(href="https://researchmap.jp/mtakaha", "高橋 将宜", target="_blank", rel="noopener noreferrer"), br(),
      br(),
      "注意事項：本ゲームは，1980年代後半に『週刊少年ジャンプ』の読者投稿コーナー「ジャンプ放送局」にて行われた「JBSクエスト」へのリスペクトを込めて制作された，ファンによる非公式の二次創作（トリビュート作品）です．", br(),
      "独自性について：当時のソースコードは非公開のため，本ゲームはJBSクエストを完全再現したものではなく，製作者がR言語を用いて独自に構築したアルゴリズムに基づいています．", br(),
      "権利関係について：株式会社集英社および当時の制作関係者様とは一切関係ありません．", br(),
      "データの引用について：モード1のキャラクター名およびパラメータ等のデータは，歴史的な記録を振り返る目的で，当時の誌面（「ジャンプ放送局」『週刊少年ジャンプ』1989年10月9日号 408～413頁，1989年10月16日号 402～407頁，1989年10月23日号 418～423頁，1990年7月30日号 402～407頁，1990年8月6日号 402～407頁，1990年8月13日号 432～437頁）で公開された情報より引用しています．", br(),
      br(),
      "最終更新日時：2026年4月1日 11:38"
  )
)

# --- サーバ ---
server <- function(input, output, session) {
  battle_state <- reactiveValues(active = FALSE, mode = 0, c1 = NULL, c2 = NULL, turn = 1, opponent_idx = 1, log = "", finished = FALSE, opps = NULL)
  
  check_stats <- function(n, h, a, d, s) {
    if (n == "" || any(is.na(c(h, a, d, s)))) return("全項目入力が必要です")
    if (any(c(h, a, d, s) < 0)) return("ステータスに負の値は入力できません")
    if (any(c(h, a, d, s) %% 1 != 0)) return("ステータスは整数で入力してください")
    if (sum(c(h, a, d, s)) > 100) return(paste0("合計100を超えています (現在:", sum(c(h, a, d, s)), ")"))
    return(NULL)
  }
  
  output$warning_m1 <- renderUI({ msg <- check_stats(input$m1_name, input$m1_hp, input$m1_atk, input$m1_def, input$m1_spd); if(!is.null(msg)) div(class="status-warning", msg) })
  output$warning_m2 <- renderUI({ 
    msg1 <- check_stats(input$m2_n1, input$m2_h1, input$m2_a1, input$m2_d1, input$m2_s1)
    msg2 <- check_stats(input$m2_n2, input$m2_h2, input$m2_a2, input$m2_d2, input$m2_s2)
    msg <- if(!is.null(msg1)) msg1 else msg2
    if(!is.null(msg)) div(class="status-warning", msg) 
  })
  
  fmt_stats <- function(unit) {
    paste0("[", unit$name, "] HP:", unit$hp, " ATK:", unit$atk, " DEF:", unit$def, " SPD:", unit$spd)
  }
  
  execute_turn <- function() {
    c1 <- battle_state$c1; c2 <- battle_state$c2
    if (c1$hp > 0 && c2$hp > 0) {
      msg <- paste0("[ターン ", battle_state$turn, "]\n")
      order <- if (((c1$spd + 1) * runif(1)) >= ((c2$spd + 1) * runif(1))) list(c1, c2) else list(c2, c1)
      for (i in 1:2) {
        atk_unit <- order[[i]]; def_unit <- if(i==1) order[[2]] else order[[1]]
        if (atk_unit$hp <= 0) next
        
        # --- 2回連続攻撃の判定 ---
        prob_double <- max(0, (atk_unit$spd - def_unit$spd) / 100) * 0.375
        num_attacks <- if(runif(1) < prob_double) 2 else 1
        
        if(num_attacks == 2) msg <- paste0(msg, atk_unit$name, " の2回連続攻撃！\n")
        
        for (hit_count in 1:num_attacks) {
          if (def_unit$hp <= 0) break
          
          evasion_rate <- max(0, def_unit$spd - atk_unit$spd)
          if (runif(1, 0, 100) < evasion_rate) {
            action_msg <- "しかし かわされた！"
          } else {
            base_dmg <- 2.72924 + 0.21367*(atk_unit$atk - def_unit$def) + rnorm(1, 0, 1.604484)
            damage <- round(base_dmg)          
            if (damage <= 0 && atk_unit$atk > 0) damage <- 1
            if (atk_unit$atk == 0) damage <- 0
            
            def_unit$hp <- max(0, def_unit$hp - damage)
            action_msg <- paste0(damage, " のダメージを与えた！")
          }
          if (def_unit$id == "c1") c1$hp <- def_unit$hp else c2$hp <- def_unit$hp
          msg <- paste0(msg, atk_unit$name, " の攻撃！ ", action_msg, "\n")
        }
        
        if (c1$hp <= 0 || c2$hp <= 0) break
      }
      msg <- paste0(msg, " (", c1$name, "のHP:", c1$hp, ", ", c2$name, "のHP:", c2$hp, ")\n")
      battle_state$c1 <- c1; battle_state$c2 <- c2
      battle_state$log <- paste0(battle_state$log, msg, "\n"); battle_state$turn <- battle_state$turn + 1
    }
    
    if (c1$hp <= 0 || c2$hp <= 0) {
      battle_state$finished <- TRUE
      winner <- if(c1$hp > 0) c1$name else c2$name
      battle_state$log <- paste0(battle_state$log, ">>>> ", winner, " の勝利！\n")
      if (battle_state$mode == 1 && winner == c1$name && battle_state$opponent_idx == 7) {
        battle_state$log <- paste0(battle_state$log, "\n祝！！ 7連勝達成！ あなたが真の王者です！\n")
      }
    }
  }
  
  observeEvent(input$start_m1, {
    req(is.null(check_stats(input$m1_name, input$m1_hp, input$m1_atk, input$m1_def, input$m1_spd)))
    
    # --- 対戦相手のランダム選出 ---
    r1 <- sample(c(1:8), 1)
    if(r1 == 1){
      OPPONENT2 <- list(name = "ザえびふりゃあ", title = "JBSクエスト ベスト8", hp=45, atk=38, def=10, spd=0)
    }else if(r1 == 2){
      OPPONENT2 <- list(name = "しんじゅへび", title = "JBSクエスト ベスト8", hp=51, atk=29, def=12, spd=8)
    }else if(r1 == 3){
      OPPONENT2 <- list(name = "かつおドラゴン", title = "JBSクエスト ベスト8", hp=37, atk=21, def=35, spd=7)
    }else if(r1 == 4){
      OPPONENT2 <- list(name = "メタルこしひかり", title = "JBSクエスト ベスト8", hp=21, atk=13, def=65, spd=1)
    }else if(r1 == 5){
      OPPONENT2 <- list(name = "だいもんじやま", title = "JBSクエスト2 ベスト8", hp=30, atk=30, def=40, spd=0)
    }else if(r1 == 6){
      OPPONENT2 <- list(name = "はなのあきんど", title = "JBSクエスト2 ベスト8", hp=25, atk=32, def=40, spd=3)
    }else if(r1 == 7){
      OPPONENT2 <- list(name = "ムシャササニシキ", title = "JBSクエスト2 ベスト8", hp=35, atk=25, def=25, spd=15)
    }else if(r1 == 8){
      OPPONENT2 <- list(name = "ぶっちゅ～りっぷ", title = "JBSクエスト2 ベスト8", hp=30, atk=30, def=20, spd=20)
    }
    
    r2 <- sample(c(1:4), 1)
    if(r2 == 1){
      OPPONENT3 <- list(name = "らっかせーキング", title = "JBSクエスト ベスト4", hp=42, atk=40, def=3, spd=15)
    }else if(r2 == 2){
      OPPONENT3 <- list(name = "てつびん28ごう", title = "JBSクエスト ベスト4", hp=42, atk=15, def=35, spd=8)
    }else if(r2 == 3){
      OPPONENT3 <- list(name = "スーちゃんくじら", title = "JBSクエスト2 ベスト4", hp=30, atk=35, def=30, spd=5)
    }else if(r2 == 4){
      OPPONENT3 <- list(name = "こっかいぎじろう", title = "JBSクエスト2 ベスト4", hp=25, atk=45, def=5, spd=25)
    }
    
    battle_state$opps <- list(
      list(name = "のみ003", title = "JBSクエスト 福岡代表", hp=1, atk=1, def=0, spd=98),
      OPPONENT2,
      OPPONENT3,
      list(name = "ラッシュやまのて", title = "JBSクエスト 準優勝", hp=34, atk=33, def=33, spd=0),
      list(name = "しらはまのすな", title = "JBSクエスト2 準優勝", hp=28, atk=48, def=12, spd=12),
      list(name = "いかりのひでよし", title = "JBSクエスト 優勝", hp=26, atk=36, def=36, spd=2),
      list(name = "うっ・マンボ", title = "JBSクエスト2 優勝", hp=26, atk=38, def=32, spd=4)
    )
    
    battle_state$active <- TRUE; battle_state$mode <- 1; battle_state$opponent_idx <- 1; battle_state$turn <- 1; battle_state$finished <- FALSE
    battle_state$c1 <- list(id="c1", name=input$m1_name, hp=input$m1_hp, atk=input$m1_atk, def=input$m1_def, spd=input$m1_spd)
    opp <- battle_state$opps[[1]]; opp$id <- "c2"
    battle_state$c2 <- opp
    battle_state$log <- paste0("=== チャレンジ開始 vs ", opp$name, "（", opp$title, "） ===\n", fmt_stats(battle_state$c1), "\n", fmt_stats(opp), "\n\n")
  })
  
  observeEvent(input$start_m2, {
    req(is.null(check_stats(input$m2_n1, input$m2_h1, input$m2_a1, input$m2_d1, input$m2_s1)))
    battle_state$active <- TRUE; battle_state$mode <- 2; battle_state$turn <- 1; battle_state$finished <- FALSE
    battle_state$c1 <- list(id="c1", name=input$m2_n1, hp=input$m2_h1, atk=input$m2_a1, def=input$m2_d1, spd=input$m2_s1)
    battle_state$c2 <- list(id="c2", name=input$m2_n2, hp=input$m2_h2, atk=input$m2_a2, def=input$m2_d2, spd=input$m2_s2)
    battle_state$log <- paste0("--- 自由対戦開始 ---\n", fmt_stats(battle_state$c1), "\n", fmt_stats(battle_state$c2), "\n\n")
  })
  
  observeEvent(input$next_turn, {
    if (!battle_state$finished) {
      execute_turn()
    } else if (battle_state$mode == 1 && battle_state$c1$hp > 0 && battle_state$opponent_idx < 7) {
      battle_state$opponent_idx <- battle_state$opponent_idx + 1
      c1 <- battle_state$c1; c1$hp <- input$m1_hp; battle_state$c1 <- c1
      opp <- battle_state$opps[[battle_state$opponent_idx]]; opp$id <- "c2"
      battle_state$c2 <- opp
      battle_state$turn <- 1; battle_state$finished <- FALSE
      battle_state$log <- paste0(battle_state$log, "=== 第", battle_state$opponent_idx, "戦 vs ", opp$name, "（", opp$title, "） ===\n",
                                 fmt_stats(battle_state$c1), "\n",
                                 fmt_stats(opp), "\n\n")
    }
  })
  
  output$log_m1 <- renderText({ req(battle_state$mode == 1); battle_state$log })
  output$log_m2 <- renderText({ req(battle_state$mode == 2); battle_state$log })
  
  btn_ui <- function(mode) {
    if(!battle_state$active || battle_state$mode != mode) return(NULL)
    if(battle_state$finished && (mode == 2 || (mode == 1 && (battle_state$c1$hp <= 0 || battle_state$opponent_idx == 7)))) return(NULL)
    label <- if(battle_state$finished) "次の試合へ進む" else "次のターンへ"
    actionButton("next_turn", label, class = "btn-warning", style="margin-top:10px; width:100%;")
  }
  output$next_btn_ui_m1 <- renderUI({ btn_ui(1) })
  output$next_btn_ui_m2 <- renderUI({ btn_ui(2) })
  
  # --- SNSシェアボタンの生成 ---
  create_share_button <- function() {
    if (!battle_state$finished) return(NULL)
    
    if (battle_state$mode == 1) {
      is_final_win <- (battle_state$opponent_idx == 7 && battle_state$c1$hp > 0)
      is_loss <- (battle_state$c1$hp <= 0)
      if (!(is_final_win || is_loss)) return(NULL)
    }
    
    winner_name <- if(battle_state$c1$hp > 0) battle_state$c1$name else battle_state$c2$name
    
    msg <- if(battle_state$mode == 1 && battle_state$opponent_idx == 7 && battle_state$c1$hp > 0) {
      paste0("JBSクエスト・トリビュートで7連勝達成！王者は「", winner_name, "」だ！")
    } else {
      paste0("JBSクエスト・トリビュートで「", winner_name, "」が勝利しました！")
    }
    
    # LINE内ブラウザ対策として openExternalBrowser=1 を付与
    app_url <- "https://mtakahashi123.github.io/jbs-quest-live/?openExternalBrowser=1" 
    tweet_url <- paste0("https://twitter.com/intent/tweet?text=", 
                        utils::URLencode(msg), 
                        "&url=", utils::URLencode(app_url),
                        "&hashtags=JBSクエスト,RShiny")
    
    tags$a(href = tweet_url, class = "btn btn-share", target = "_blank", "結果をXでシェア")
  }
  
  output$share_ui_m1 <- renderUI({ create_share_button() })
  output$share_ui_m2 <- renderUI({ create_share_button() })
}

shinyApp(ui = ui, server = server)
